-- test_item_detail 测试核心细节主表 v2（全量扩展）
CREATE TABLE IF NOT EXISTS test_item_detail (
  project_code VARCHAR(64) NOT NULL DEFAULT 'fitness-agent',
  project_name VARCHAR(255) NOT NULL DEFAULT 'Fitness Agent 测试项目',
  item_id VARCHAR(64) PRIMARY KEY,
  dimension_id CHAR(1) NOT NULL REFERENCES test_dimension(dimension_id),
  category_major_id VARCHAR(32) NOT NULL REFERENCES test_category_major(category_major_id),
  category_minor_id VARCHAR(64) NOT NULL REFERENCES test_category_minor(category_minor_id),
  sub_class VARCHAR(128),
  item_name VARCHAR(512) NOT NULL,
  detail_summary TEXT NOT NULL,
  expected_observation TEXT,
  test_input_example TEXT,
  preconditions JSONB NOT NULL DEFAULT '[]',
  test_steps JSONB NOT NULL DEFAULT '[]',
  assertion_points JSONB NOT NULL DEFAULT '[]',
  priority_id VARCHAR(4) NOT NULL REFERENCES test_priority_enum(priority_id),
  prd_ref_id VARCHAR(32) REFERENCES prd_reference(prd_ref_id),
  prd_ref_ids JSONB NOT NULL DEFAULT '[]',
  arch_ref_id VARCHAR(32) REFERENCES arch_reference(arch_ref_id),
  arch_ref_ids JSONB NOT NULL DEFAULT '[]',
  prd_goal_ids JSONB NOT NULL DEFAULT '[]',
  automation_status_id VARCHAR(32) NOT NULL REFERENCES test_automation_status_enum(automation_status_id),
  automation_entry_id VARCHAR(32) REFERENCES automation_entry_enum(automation_entry_id),
  automation_command TEXT,
  config_env VARCHAR(256),
  config_env_id VARCHAR(64) REFERENCES config_env_enum(config_env_id),
  station_id VARCHAR(8) NOT NULL DEFAULT 'NONE' REFERENCES test_station_enum(station_id),
  role_scope_id VARCHAR(16) NOT NULL DEFAULT 'ALL' REFERENCES test_role_enum(role_scope_id),
  endpoint_path VARCHAR(256),
  http_method VARCHAR(8),
  http_status_expected SMALLINT,
  scheme_primary_id VARCHAR(16) REFERENCES test_scheme_enum(scheme_id),
  scheme_secondary_id VARCHAR(16) REFERENCES test_scheme_enum(scheme_id),
  validation_primary_id VARCHAR(20) REFERENCES test_validation_enum(validation_id),
  validation_secondary_id VARCHAR(20) REFERENCES test_validation_enum(validation_id),
  sample_execution_note TEXT,
  scheme_mapping_source VARCHAR(128),
  is_risk_flag BOOLEAN NOT NULL DEFAULT FALSE,
  is_observability_audit BOOLEAN NOT NULL DEFAULT FALSE,
  is_p0_blocker BOOLEAN NOT NULL DEFAULT FALSE,
  failure_symptom TEXT,
  code_reference VARCHAR(256),
  tags JSONB NOT NULL DEFAULT '[]',
  notes TEXT,
  source_doc VARCHAR(128) NOT NULL,
  source_section VARCHAR(32),
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  exec_env_id VARCHAR(32) NOT NULL DEFAULT 'EXEC_BOTH' REFERENCES test_exec_env_enum(exec_env_id),
  env_tier_id VARCHAR(32) NOT NULL DEFAULT 'TIER_STAGING' REFERENCES test_env_tier_enum(env_tier_id),
  generation_job_id INT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_test_item_major ON test_item_detail(category_major_id);
CREATE INDEX IF NOT EXISTS idx_test_item_minor ON test_item_detail(category_minor_id);
CREATE INDEX IF NOT EXISTS idx_test_item_scheme ON test_item_detail(scheme_primary_id);
CREATE INDEX IF NOT EXISTS idx_test_item_validation ON test_item_detail(validation_primary_id);
CREATE INDEX IF NOT EXISTS idx_test_item_station ON test_item_detail(station_id);
CREATE INDEX IF NOT EXISTS idx_test_item_role ON test_item_detail(role_scope_id);
CREATE INDEX IF NOT EXISTS idx_test_item_risk ON test_item_detail(is_risk_flag) WHERE is_risk_flag;
CREATE INDEX IF NOT EXISTS idx_test_item_p0 ON test_item_detail(is_p0_blocker) WHERE is_p0_blocker;
CREATE INDEX IF NOT EXISTS idx_test_item_exec_env ON test_item_detail(exec_env_id);
CREATE INDEX IF NOT EXISTS idx_test_item_env_tier ON test_item_detail(env_tier_id);
CREATE INDEX IF NOT EXISTS idx_test_item_generation_job ON test_item_detail(generation_job_id);

